#include <bits/stdc++.h>
using namespace std;

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int N;
    cin >> N;

    const int INF = 1e9;
    vector<int> dist(N + 1, INF);
    vector<int> prev_op(N + 1, 0); // which operation led here from previous number

    dist[1] = 0;
    // BFS from 1 forward (since operations increase value)
    queue<int> q;
    q.push(1);
    while (!q.empty()) {
        int x = q.front();
        q.pop();
        int d = dist[x];
        // op1: +1
        if (x + 1 <= N && dist[x + 1] > d + 1) {
            dist[x + 1] = d + 1;
            prev_op[x + 1] = 1;
            q.push(x + 1);
        }
        // op2: *2
        if (x * 2 <= N && dist[x * 2] > d + 1) {
            dist[x * 2] = d + 1;
            prev_op[x * 2] = 2;
            q.push(x * 2);
        }
        // op3: *3
        if (x * 3 <= N && dist[x * 3] > d + 1) {
            dist[x * 3] = d + 1;
            prev_op[x * 3] = 3;
            q.push(x * 3);
        }
    }

    // Now reconstruct the sequence.
    // However, we need to break ties correctly: among equally-short sequences,
    // choose the one whose reversed sequence is lexicographically largest.
    // The BFS above uses first-come-first-serve tie-breaking, which may not
    // match the required tie-breaker. We need to re-examine.
    //
    // Let's compute the optimal sequence via DP with tie-breaking on reversed order.
    // We'll store the best sequence (as string) for each number.

    vector<string> seq(N + 1);
    vector<int> best_dist(N + 1, INF);
    best_dist[1] = 0;
    seq[1] = "";

    // We can process numbers from 1 to N, since operations increase value.
    // For each x, try to update its successors.
    for (int x = 1; x <= N; ++x) {
        if (best_dist[x] == INF) continue;
        int d = best_dist[x];
        const string &cur = seq[x];

        // op1: +1
        int y = x + 1;
        if (y <= N) {
            string cand = cur + "1";
            if (d + 1 < best_dist[y]) {
                best_dist[y] = d + 1;
                seq[y] = cand;
            } else if (d + 1 == best_dist[y]) {
                // tie-break: reversed cand vs reversed seq[y], larger wins
                string rev_cand = cand;
                reverse(rev_cand.begin(), rev_cand.end());
                string rev_cur = seq[y];
                reverse(rev_cur.begin(), rev_cur.end());
                if (rev_cand > rev_cur) {
                    seq[y] = cand;
                }
            }
        }

        // op2: *2
        y = x * 2;
        if (y <= N) {
            string cand = cur + "2";
            if (d + 1 < best_dist[y]) {
                best_dist[y] = d + 1;
                seq[y] = cand;
            } else if (d + 1 == best_dist[y]) {
                string rev_cand = cand;
                reverse(rev_cand.begin(), rev_cand.end());
                string rev_cur = seq[y];
                reverse(rev_cur.begin(), rev_cur.end());
                if (rev_cand > rev_cur) {
                    seq[y] = cand;
                }
            }
        }

        // op3: *3
        y = x * 3;
        if (y <= N) {
            string cand = cur + "3";
            if (d + 1 < best_dist[y]) {
                best_dist[y] = d + 1;
                seq[y] = cand;
            } else if (d + 1 == best_dist[y]) {
                string rev_cand = cand;
                reverse(rev_cand.begin(), rev_cand.end());
                string rev_cur = seq[y];
                reverse(rev_cur.begin(), rev_cur.end());
                if (rev_cand > rev_cur) {
                    seq[y] = cand;
                }
            }
        }
    }

    cout << best_dist[N] << "\n";
    cout << seq[N] << "\n";

    return 0;
}
